import React from 'react';
import '../styles/components/Footer.css';

function Footer() {
  return (
    <footer className="footer">
      <div className="container">
        <p>
          Designed & Built by <span>Cellonita Farida Putri</span> © 2024
        </p>
      </div>
    </footer>
  );
}

export default Footer;
